import{_ as a,o as n,c as e,a2 as l}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Static Linking","description":"Produce fully self-contained binaries with no runtime dependencies by statically linking system libraries and using musl on Linux.","frontmatter":{"title":"Static Linking","description":"Produce fully self-contained binaries with no runtime dependencies by statically linking system libraries and using musl on Linux."},"headers":[],"relativePath":"learn/linear/17-packaging-and-distribution/03-static-linking.md","filePath":"learn/linear/17-packaging-and-distribution/03-static-linking.md"}'),t={name:"learn/linear/17-packaging-and-distribution/03-static-linking.md"};function o(p,s,i,c,r,y){return n(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="static-linking" tabindex="-1">Static Linking <a class="header-anchor" href="#static-linking" aria-label="Permalink to &quot;Static Linking&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to statically link common dependencies (OpenSSL via rustls, libgit2 via the git2 crate&#39;s vendored feature) to eliminate runtime library requirements</li><li>Techniques for building fully static Linux binaries using musl libc, including the tradeoffs with glibc compatibility</li><li>How to verify that your binary is truly self-contained using tools like ldd, otool, and file to check for dynamic library dependencies</li></ul></blockquote><p>When you hand someone a binary, you want it to work. Not &quot;works if you install libssl 1.1&quot; or &quot;works if your glibc is at least 2.28.&quot; A statically linked binary contains everything it needs to run -- all library code is baked into the single executable file. The user downloads it, marks it executable, and runs it. No package manager, no dependency resolution, no &quot;it works on my machine.&quot; This is one of Rust&#39;s greatest practical advantages for CLI tools, and this subchapter shows you how to achieve it.</p><h2 id="dynamic-vs-static-linking" tabindex="-1">Dynamic vs. Static Linking <a class="header-anchor" href="#dynamic-vs-static-linking" aria-label="Permalink to &quot;Dynamic vs. Static Linking&quot;">​</a></h2><p>By default, Rust statically links all Rust code but dynamically links system libraries. On Linux, even a &quot;hello world&quot; binary dynamically links to libc:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Build a default release binary</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check dynamic dependencies on Linux</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ldd</span><span style="color:#A6E3A1;"> target/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   linux-vdso.so.1 (0x00007ffcc3bfe000)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   libgcc_s.so.1 =&gt; /lib/x86_64-linux-gnu/libgcc_s.so.1</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   libc.so.6 =&gt; /lib/x86_64-linux-gnu/libc.so.6</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   /lib64/ld-linux-x86-64.so.2</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check on macOS</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">otool</span><span style="color:#A6E3A1;"> -L</span><span style="color:#A6E3A1;"> target/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   /usr/lib/libSystem.B.dylib</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   /usr/lib/libresolv.9.dylib</span></span></code></pre></div><p>Those dynamic dependencies mean your binary needs compatible versions of those libraries on the target system. For libc, this is usually fine -- every Linux system has it. But if your agent links to OpenSSL, libgit2, or libsqlite3, you are asking users to install specific library versions.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>The Python equivalent of this problem is the infamous <code>pip install cryptography</code> failure, where the user doesn&#39;t have OpenSSL development headers, or has the wrong version. The <code>manylinux</code> wheel standard exists to bundle pre-compiled shared libraries inside Python wheels. Rust&#39;s approach is simpler: statically link everything and ship a single binary. No shared library search paths, no <code>LD_LIBRARY_PATH</code> hacks, no <code>delocate</code> or <code>auditwheel</code> post-processing.</p></div><h2 id="strategy-1-use-pure-rust-alternatives" tabindex="-1">Strategy 1: Use Pure Rust Alternatives <a class="header-anchor" href="#strategy-1-use-pure-rust-alternatives" aria-label="Permalink to &quot;Strategy 1: Use Pure Rust Alternatives&quot;">​</a></h2><p>The cleanest way to eliminate dynamic dependencies is to avoid C libraries entirely. The Rust ecosystem provides pure-Rust replacements for the most common C dependencies:</p><table tabindex="0"><thead><tr><th>C Library</th><th>Rust Alternative</th><th>How to Switch</th></tr></thead><tbody><tr><td>OpenSSL (libssl)</td><td><code>rustls</code></td><td>Use <code>reqwest</code> with <code>rustls-tls</code> feature</td></tr><tr><td>libcurl</td><td><code>reqwest</code> / <code>hyper</code></td><td>Already pure Rust (with rustls)</td></tr><tr><td>libgit2</td><td><code>gitoxide</code> (<code>gix</code>)</td><td>Replace <code>git2</code> crate with <code>gix</code></td></tr><tr><td>libsqlite3</td><td><code>rusqlite</code> bundled</td><td>Enable <code>bundled</code> feature flag</td></tr><tr><td>libz (zlib)</td><td><code>flate2</code> with <code>rust_backend</code></td><td>Feature flag on <code>flate2</code></td></tr></tbody></table><p>For our coding agent, the key change is the HTTP client:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Instead of this (links to system OpenSSL):</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># reqwest = { version = &quot;0.12&quot;, features = [&quot;json&quot;] }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Use this (pure Rust TLS):</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> default-features </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;rustls-tls&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;json&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;stream&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;http2&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>The <code>default-features = false</code> is important. Without it, <code>reqwest</code> may pull in <code>native-tls</code>, which links to OpenSSL on Linux or Security.framework on macOS. With <code>rustls-tls</code>, all TLS is handled by pure Rust code -- no system libraries needed.</p><h2 id="strategy-2-vendor-c-dependencies" tabindex="-1">Strategy 2: Vendor C Dependencies <a class="header-anchor" href="#strategy-2-vendor-c-dependencies" aria-label="Permalink to &quot;Strategy 2: Vendor C Dependencies&quot;">​</a></h2><p>When a pure Rust alternative is not available or not mature enough, you can vendor the C dependency. Vendoring means compiling the C source code as part of your Rust build, producing a static library that gets linked into your binary:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Vendor libgit2: compiles from C source during cargo build</span></span>
<span class="line"><span style="color:#CDD6F4;">git2 </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.19&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;vendored&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Vendor SQLite: compiles from the amalgamation C file</span></span>
<span class="line"><span style="color:#CDD6F4;">rusqlite </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.32&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;bundled&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Vendor zlib</span></span>
<span class="line"><span style="color:#CDD6F4;">flate2 </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;zlib-ng&quot;</span><span style="color:#9399B2;">],</span><span style="color:#CDD6F4;"> default-features </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#9399B2;"> }</span></span></code></pre></div><p>With vendored builds, the C code is compiled by the <code>cc</code> crate using whatever C compiler is available on the build system. For native builds, this is your system&#39;s <code>gcc</code> or <code>clang</code>. For cross-compilation, you need a cross-compiler (which is why <code>cross</code> and <code>cargo-zigbuild</code> are so useful -- they provide this automatically).</p><h2 id="strategy-3-musl-libc-for-fully-static-linux-binaries" tabindex="-1">Strategy 3: Musl libc for Fully Static Linux Binaries <a class="header-anchor" href="#strategy-3-musl-libc-for-fully-static-linux-binaries" aria-label="Permalink to &quot;Strategy 3: Musl libc for Fully Static Linux Binaries&quot;">​</a></h2><p>The most impactful step for Linux distribution is switching from glibc to musl libc. Musl is a lightweight, static-linking-friendly libc implementation. When you target <code>x86_64-unknown-linux-musl</code>, the Rust compiler statically links musl libc into your binary, producing a truly standalone executable:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Add the musl target</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> target</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Install musl tools (Ubuntu/Debian)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">sudo</span><span style="color:#A6E3A1;"> apt</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> musl-tools</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build a fully static binary</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Verify it is fully static</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ldd</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   not a dynamic executable</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">file</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   ELF 64-bit LSB executable, x86-64, version 1 (SYSV),</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">#   statically linked, stripped</span></span></code></pre></div><p>That <code>not a dynamic executable</code> output from <code>ldd</code> is what you want to see. This binary runs on any Linux system regardless of the installed glibc version, distribution, or architecture compatibility layer.</p><h3 id="musl-tradeoffs" tabindex="-1">Musl Tradeoffs <a class="header-anchor" href="#musl-tradeoffs" aria-label="Permalink to &quot;Musl Tradeoffs&quot;">​</a></h3><p>Musl is not a drop-in replacement for glibc in all cases. Here are the tradeoffs:</p><table tabindex="0"><thead><tr><th>Aspect</th><th>glibc</th><th>musl</th></tr></thead><tbody><tr><td>DNS resolution</td><td>Full NSS support (LDAP, NIS, mDNS)</td><td>Simple resolver (DNS only)</td></tr><tr><td>Locale support</td><td>Full locale/i18n support</td><td>Minimal locale handling</td></tr><tr><td>Performance</td><td>Optimized allocator (ptmalloc2)</td><td>Simpler allocator</td></tr><tr><td>Binary size</td><td>Dynamic linking reduces per-binary size</td><td>Larger binaries (libc is baked in)</td></tr><tr><td>Compatibility</td><td>Standard on virtually all Linux distros</td><td>Runs anywhere, but some edge cases</td></tr></tbody></table><p>For a coding agent, the DNS and locale limitations rarely matter. Your agent makes HTTPS requests to API endpoints (DNS works fine) and processes code files (locale-dependent string sorting is not a concern). The portability benefit far outweighs the edge cases.</p><h3 id="combining-musl-with-pure-rust-dependencies" tabindex="-1">Combining Musl with Pure Rust Dependencies <a class="header-anchor" href="#combining-musl-with-pure-rust-dependencies" aria-label="Permalink to &quot;Combining Musl with Pure Rust Dependencies&quot;">​</a></h3><p>The ideal configuration for maximum portability combines musl with pure-Rust dependencies:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">reqwest </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.12&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> default-features </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> false</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">    &quot;rustls-tls&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;json&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;stream&quot;</span></span>
<span class="line"><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">tokio </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;full&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">serde </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#CDD6F4;"> version </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> features </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;derive&quot;</span><span style="color:#9399B2;">]</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#CDD6F4;">serde_json </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;1&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">profile.release</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">opt-level </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 3</span></span>
<span class="line"><span style="color:#CDD6F4;">lto </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;fat&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">codegen-units </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CDD6F4;">panic </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;abort&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">strip </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;symbols&quot;</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> x86_64-unknown-linux-musl</span></span></code></pre></div><p>This produces a binary with zero dynamic dependencies. No libc, no libssl, no libcrypto, nothing. Copy it to any x86_64 Linux machine and it runs.</p><h2 id="verifying-your-binary" tabindex="-1">Verifying Your Binary <a class="header-anchor" href="#verifying-your-binary" aria-label="Permalink to &quot;Verifying Your Binary&quot;">​</a></h2><p>Always verify that your release binary is truly self-contained before distributing it. Here are the platform-specific tools:</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Check for dynamic dependencies</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ldd</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Expected: &quot;not a dynamic executable&quot; or &quot;statically linked&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check binary type</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">file</span><span style="color:#A6E3A1;"> target/x86_64-unknown-linux-musl/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Expected: &quot;ELF 64-bit LSB executable, ... statically linked&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># List symbols (if not stripped)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">nm</span><span style="color:#A6E3A1;"> target/release/my-agent</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> head</span><span style="color:#A6E3A1;"> -20</span></span></code></pre></div><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Check dynamic library dependencies</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">otool</span><span style="color:#A6E3A1;"> -L</span><span style="color:#A6E3A1;"> target/release/my-agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Minimal: just /usr/lib/libSystem.B.dylib (always needed on macOS)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check if the binary is signed</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">codesign</span><span style="color:#A6E3A1;"> -dv</span><span style="color:#A6E3A1;"> target/release/my-agent</span></span></code></pre></div><p>On macOS, fully static binaries are not possible -- Apple requires linking to <code>libSystem.B.dylib</code>. However, this library is guaranteed to be present on every macOS installation, so it is not a practical concern.</p><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Check dependencies using dumpbin (from Visual Studio)</span></span>
<span class="line"><span style="color:#CDD6F4;">dumpbin </span><span style="color:#94E2D5;">/</span><span style="color:#CDD6F4;">dependents target\\release\\</span><span style="color:#89B4FA;font-style:italic;">my-agent.exe</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Expected: KERNEL32.dll, ntdll.dll (always present on Windows)</span></span></code></pre></div><h2 id="automated-verification-in-ci" tabindex="-1">Automated Verification in CI <a class="header-anchor" href="#automated-verification-in-ci" aria-label="Permalink to &quot;Automated Verification in CI&quot;">​</a></h2><p>Add a verification step to your CI pipeline that catches accidental dynamic dependencies:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">-</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Verify static binary (Linux musl)</span></span>
<span class="line"><span style="color:#89B4FA;">  if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> contains(matrix.target, &#39;musl&#39;)</span></span>
<span class="line"><span style="color:#89B4FA;">  run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">    # This fails if the binary has any dynamic dependencies</span></span>
<span class="line"><span style="color:#A6E3A1;">    ldd target/\${{ matrix.target }}/release/my-agent 2&gt;&amp;1 | \\</span></span>
<span class="line"><span style="color:#A6E3A1;">      grep -q &quot;not a dynamic executable&quot; || \\</span></span>
<span class="line"><span style="color:#A6E3A1;">      (echo &quot;ERROR: Binary has dynamic dependencies!&quot; &amp;&amp; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">       ldd target/\${{ matrix.target }}/release/my-agent &amp;&amp; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">       exit 1)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">-</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Verify binary type</span></span>
<span class="line"><span style="color:#89B4FA;">  run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">    file target/\${{ matrix.target }}/release/my-agent</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Production CLI tools in the Rust ecosystem almost universally use musl for Linux distribution. Tools like ripgrep, fd, bat, and delta all ship static musl binaries. The pattern is well-established: musl for Linux portability, pure-Rust TLS for zero OpenSSL dependency, and vendored C libraries for anything that must remain in C.</p></div><h2 id="a-complete-static-build-script" tabindex="-1">A Complete Static Build Script <a class="header-anchor" href="#a-complete-static-build-script" aria-label="Permalink to &quot;A Complete Static Build Script&quot;">​</a></h2><p>Here is a build script that produces verified static binaries for Linux:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/bash</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">set</span><span style="color:#A6E3A1;"> -euo</span><span style="color:#A6E3A1;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">BINARY_NAME</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;my-agent&quot;</span></span>
<span class="line"><span style="color:#CDD6F4;">TARGET</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;x86_64-unknown-linux-musl&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Building static binary for </span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">...&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> build</span><span style="color:#A6E3A1;"> --release</span><span style="color:#A6E3A1;"> --target</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">BINARY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;target/</span><span style="color:#CDD6F4;">\${TARGET}</span><span style="color:#A6E3A1;">/release/</span><span style="color:#CDD6F4;">\${BINARY_NAME}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Verifying binary...&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">file</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Check it is static</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#89B4FA;font-style:italic;"> ldd</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#94E2D5;"> 2&gt;&amp;1</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> grep</span><span style="color:#A6E3A1;"> -q</span><span style="color:#A6E3A1;"> &quot;not a dynamic executable&quot;</span><span style="color:#9399B2;">;</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;Binary is fully static&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">else</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;WARNING: Binary has dynamic dependencies:&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    ldd</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    exit</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Show size</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ls</span><span style="color:#A6E3A1;"> -lh</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">echo</span><span style="color:#A6E3A1;"> &quot;Build complete: </span><span style="color:#CDD6F4;">\${BINARY}</span><span style="color:#A6E3A1;">&quot;</span></span></code></pre></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Static linking produces self-contained binaries with zero runtime dependencies -- users download one file and it works.</li><li>Prefer pure Rust alternatives to C libraries: <code>rustls</code> over OpenSSL, <code>gix</code> over <code>git2</code>, <code>bundled</code> features for SQLite.</li><li>Target <code>x86_64-unknown-linux-musl</code> (or <code>aarch64-unknown-linux-musl</code>) for fully static Linux binaries that run on any distribution.</li><li>Musl has minor limitations (simplified DNS resolver, minimal locale support) that rarely affect CLI tools.</li><li>Always verify your binary with <code>ldd</code> (Linux), <code>otool</code> (macOS), or <code>dumpbin</code> (Windows) before distribution to catch accidental dynamic dependencies.</li></ul>`,49)])])}const h=a(t,[["render",o]]);export{u as __pageData,h as default};
